// Cloudflare Worker with SendGrid and Stripe Integration

const ALLOWED_ORIGINS = ['https://yourdomain.com', 'https://www.yourdomain.com'];

const RATE_LIMIT_WINDOW = 60000;
const RATE_LIMIT_MAX_REQUESTS = 100;

const rateLimitStore = new Map();

function corsHeaders(origin) {
  const allowedOrigin = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    'Access-Control-Allow-Origin': allowedOrigin,
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-API-Key',
    'Access-Control-Max-Age': '86400',
  };
}

function sanitizeInput(input) {
  if (typeof input === 'string') {
    return input.trim().slice(0, 1000);
  }
  return input;
}

function validateEmail(email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

async function checkRateLimit(identifier, env) {
  const now = Date.now();
  const key = `ratelimit:${identifier}`;
  
  try {
    const stored = await env.RATE_LIMIT_KV.get(key, { type: 'json' });
    
    if (stored) {
      const { count, timestamp } = stored;
      
      if (now - timestamp < RATE_LIMIT_WINDOW) {
        if (count >= RATE_LIMIT_MAX_REQUESTS) {
          return false;
        }
        await env.RATE_LIMIT_KV.put(key, JSON.stringify({
          count: count + 1,
          timestamp
        }), { expirationTtl: 120 });
      } else {
        await env.RATE_LIMIT_KV.put(key, JSON.stringify({
          count: 1,
          timestamp: now
        }), { expirationTtl: 120 });
      }
    } else {
      await env.RATE_LIMIT_KV.put(key, JSON.stringify({
        count: 1,
        timestamp: now
      }), { expirationTtl: 120 });
    }
    
    return true;
  } catch (error) {
    console.error('Rate limit check error:', error);
    return true;
  }
}

async function verifyApiKey(request, env) {
  const apiKey = request.headers.get('X-API-Key');
  
  if (!apiKey) {
    return false;
  }
  
  const validKey = await env.API_KEYS_KV.get(apiKey);
  return validKey !== null;
}

async function sendEmail(data, env) {
  const { to, subject, text, html } = data;
  
  if (!validateEmail(to)) {
    throw new Error('Invalid email address');
  }
  
  const sanitizedSubject = sanitizeInput(subject);
  const sanitizedText = sanitizeInput(text);
  
  const emailData = {
    personalizations: [{
      to: [{ email: to }]
    }],
    from: { email: env.SENDGRID_FROM_EMAIL },
    subject: sanitizedSubject,
    content: [
      { type: 'text/plain', value: sanitizedText }
    ]
  };
  
  if (html) {
    emailData.content.push({
      type: 'text/html',
      value: sanitizeInput(html)
    });
  }
  
  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(emailData)
  });
  
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`SendGrid API error: ${response.status} - ${errorText}`);
  }
  
  return { success: true, message: 'Email sent successfully' };
}

async function createPaymentIntent(data, env) {
  const { amount, currency = 'usd', description, metadata = {} } = data;
  
  if (!amount || amount < 50) {
    throw new Error('Invalid amount. Minimum is 50 cents.');
  }
  
  if (amount > 99999999) {
    throw new Error('Amount exceeds maximum allowed value');
  }
  
  const sanitizedDescription = sanitizeInput(description);
  
  const sanitizedMetadata = {};
  for (const [key, value] of Object.entries(metadata)) {
    if (Object.keys(sanitizedMetadata).length >= 50) break;
    sanitizedMetadata[sanitizeInput(key)] = sanitizeInput(String(value));
  }
  
  const params = new URLSearchParams({
    amount: Math.round(amount),
    currency: currency.toLowerCase(),
    'automatic_payment_methods[enabled]': 'true'
  });
  
  if (sanitizedDescription) {
    params.append('description', sanitizedDescription);
  }
  
  for (const [key, value] of Object.entries(sanitizedMetadata)) {
    params.append(`metadata[${key}]`, value);
  }
  
  const response = await fetch('https://api.stripe.com/v1/payment_intents', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: params.toString()
  });
  
  const result = await response.json();
  
  if (!response.ok) {
    throw new Error(`Stripe API error: ${result.error?.message || 'Unknown error'}`);
  }
  
  return {
    success: true,
    clientSecret: result.client_secret,
    paymentIntentId: result.id
  };
}

async function retrievePaymentIntent(paymentIntentId, env) {
  const sanitizedId = sanitizeInput(paymentIntentId);
  
  if (!sanitizedId || !/^pi_[a-zA-Z0-9]+$/.test(sanitizedId)) {
    throw new Error('Invalid payment intent ID');
  }
  
  const response = await fetch(`https://api.stripe.com/v1/payment_intents/${sanitizedId}`, {
    method: 'GET',
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`
    }
  });
  
  const result = await response.json();
  
  if (!response.ok) {
    throw new Error(`Stripe API error: ${result.error?.message || 'Unknown error'}`);
  }
  
  return {
    success: true,
    status: result.status,
    amount: result.amount,
    currency: result.currency,
    metadata: result.metadata
  };
}

async function handleWebhook(request, env) {
  const signature = request.headers.get('stripe-signature');
  
  if (!signature) {
    throw new Error('Missing Stripe signature');
  }
  
  const body = await request.text();
  
  const elements = signature.split(',');
  const timestamp = elements.find(e => e.startsWith('t=')).split('=')[1];
  const signatures = elements.filter(e => e.startsWith('v1=')).map(e => e.split('=')[1]);
  
  const signedPayload = `${timestamp}.${body}`;
  
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw',
    encoder.encode(env.STRIPE_WEBHOOK_SECRET),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  
  const signatureBuffer = await crypto.subtle.sign(
    'HMAC',
    key,
    encoder.encode(signedPayload)
  );
  
  const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');
  
  const isValid = signatures.some(sig => sig === expectedSignature);
  
  if (!isValid) {
    throw new Error('Invalid webhook signature');
  }
  
  const event = JSON.parse(body);
  
  console.log('Webhook event received:', event.type);
  
  switch (event.type) {
    case 'payment_intent.succeeded':
      console.log('Payment succeeded:', event.data.object.id);
      break;
    case 'payment_intent.payment_failed':
      console.log('Payment failed:', event.data.object.id);
      break;
    default:
      console.log('Unhandled event type:', event.type);
  }
  
  return { success: true, received: true };
}

async function handleRequest(request, env, ctx) {
  const url = new URL(request.url);
  const origin = request.headers.get('Origin');
  
  if (request.method === 'OPTIONS') {
    return new Response(null, {
      status: 204,
      headers: corsHeaders(origin)
    });
  }
  
  const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
  
  const rateLimitPassed = await checkRateLimit(clientIP, env);
  if (!rateLimitPassed) {
    return new Response(JSON.stringify({ error: 'Rate limit exceeded' }), {
      status: 429,
      headers: {
        'Content-Type': 'application/json',
        ...corsHeaders(origin)
      }
    });
  }
  
  if (url.pathname === '/webhook/stripe') {
    try {
      const result = await handleWebhook(request, env);
      return new Response(JSON.stringify(result), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    } catch (error) {
      console.error('Webhook error:', error);
      return new Response(JSON.stringify({ error: error.message }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
  
  const isAuthorized = await verifyApiKey(request, env);
  if (!isAuthorized) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), {
      status: 401,
      headers: {
        'Content-Type': 'application/json',
        ...corsHeaders(origin)
      }
    });
  }
  
  try {
    let result;
    
    if (url.pathname === '/api/send-email' && request.method === 'POST') {
      const data = await request.json();
      result = await sendEmail(data, env);
      
    } else if (url.pathname === '/api/create-payment-intent' && request.method === 'POST') {
      const data = await request.json();
      result = await createPaymentIntent(data, env);
      
    } else if (url.pathname === '/api/payment-intent' && request.method === 'GET') {
      const paymentIntentId = url.searchParams.get('id');
      if (!paymentIntentId) {
        throw new Error('Payment intent ID is required');
      }
      result = await retrievePaymentIntent(paymentIntentId, env);
      
    } else if (url.pathname === '/api/health' && request.method === 'GET') {
      result = { status: 'healthy', timestamp: new Date().toISOString() };
      
    } else {
      return new Response(JSON.stringify({ error: 'Not found' }), {
        status: 404,
        headers: {
          'Content-Type': 'application/json',
          ...corsHeaders(origin)
        }
      });
    }
    
    return new Response(JSON.stringify(result), {
      status: 200,
      headers: {
        'Content-Type': 'application/json',
        ...corsHeaders(origin)
      }
    });
    
  } catch (error) {
    console.error('Error:', error);
    
    return new Response(JSON.stringify({
      error: error.message || 'Internal server error'
    }), {
      status: error.message.includes('Invalid') ? 400 : 500,
      headers: {
        'Content-Type': 'application/json',
        ...corsHeaders(origin)
      }
    });
  }
}

export default {
  async fetch(request, env, ctx) {
    return handleRequest(request, env, ctx);
  }
};